207→function createToolInputEvent(
208→  toolName: string,
209→  toolCallChunks: AIMessageChunk['tool_call_chunks'],
210→  node: ENodeName | undefined,
211→  subagent?: StreamSubagentInfo,
212→): IGraphEvent | undefined {
213→  if (!shouldEmitToolInputPreview(toolName)) {
214→    return undefined;
215→  }
216→
217→  return makeEvent(
218→    'tool-input',
219→    node,
220→    { name: toolName, input: getToolArgs(toolCallChunks) },
221→    subagent,
222→  );
