391→export function handleChainError(
392→  name: string,
393→  data: { error?: unknown },
394→  node: ENodeName | undefined,
395→  subagent?: StreamSubagentInfo,
396→): IGraphEvent | undefined {
397→  if (!node || !(TalkableAgents as string[]).includes(name)) return undefined;
398→  const message = extractToolError(data.error) ?? tryJSONStringify(data.error) ?? 'Agent execution failed';
399→  log(`agent-error: ${name} - ${message}`);
400→  return makeEvent('agent-end', node, { name, error: message }, subagent);
