446→export function dispatchStreamEvent(
447→  event: string,
448→  ctx: StreamContext,
449→  state: ToolInputState,
450→): IGraphEvent | undefined {
451→  const { run_id, name, data, node, metadata } = ctx;
452→  const subagent = buildSubagentInfo(name, data, metadata, state);
453→
454→  // 默认关闭流式调试，避免敏感数据落盘与同步 IO 阻塞。
455→  writeStreamDebugLog(event, name, node, data);
456→
457→  switch (event) {
458→    case 'on_chain_start':
459→      return handleChainStart(name, node, subagent);
460→    case 'on_chain_end':
461→      return handleChainEnd(name, node, subagent);
462→    case 'on_chain_error':
463→      return handleChainError(name, data as { error?: unknown }, node, subagent);
464→    case 'on_chat_model_start':
465→      return handleChatModelStart(node, subagent);
466→    case 'on_chat_model_end':
467→      return handleChatModelEnd(node, data, subagent);
468→    case 'on_chat_model_error':
469→      return handleChatModelError(node, data as { error?: unknown }, subagent);
470→    case 'on_chat_model_stream':
471→      return handleChatModelStream(data as { chunk: unknown }, node, state, subagent);
472→    case 'on_chain_stream':
473→      return handleChainStream(data as { chunk?: Record<string, unknown> }, node, subagent);
474→    case 'on_tool_start':
475→      return handleToolStart(
476→        run_id,
477→        name,
478→        data as { input: { input: string } },
479→        node,
480→        state,
481→        subagent,
482→      );
483→    case 'on_tool_end':
484→      return handleToolEnd(
485→        run_id,
486→        name,
487→        data as { output: { artifact: unknown; content: unknown } },
488→        node,
489→        subagent,
490→      );
491→    case 'on_tool_error':
492→      return handleToolError(
493→        run_id,
494→        name,
495→        data as { error?: unknown },
496→        node,
497→        subagent,
498→      );
499→    default:
500→      return undefined;
501→  }
502→}
