 1→export function formatDate(date: number | Date) {
 2→  if (typeof date === 'number') {
 3→    date = new Date(date);
 4→  }
 5→  const year = date.getFullYear();
 6→  const month = String(date.getMonth() + 1).padStart(2, '0'); // 月份补零
 7→  const day = String(date.getDate()).padStart(2, '0'); // 日期补零
 8→  return `${year}-${month}-${day}`;
