33→export interface IRetryOptions {
34→  interval?: number;
35→  max?: number;
36→}
37→
38→export function retry<T>(action: () => Promise<T>, { interval, max = 32 }: IRetryOptions = {}) {
39→  let count = 0;
40→
41→  return function wrap(): Promise<T> {
42→    return action().catch(error => {
43→      if (count === max) {
44→        throw error;
45→      }
46→
47→      count++;
48→      if (interval) {
49→        return new Promise(resolve => setTimeout(resolve, interval)).then(wrap);
50→      } else {
51→        return wrap();
52→      }
53→    });
54→  };
55→}
