 16→const VFS_RELATIVE_PATH_PROMPT = `## Important: Use Relative Paths in Execute Tool
 17→
 18→The sandbox environment does NOT support absolute paths in shell commands.
 19→When using the \`execute\` tool, you MUST use **relative paths** (without leading \`/\`) for all file operations.
 20→
 21→For example:
 22→- CORRECT: \`execute(command="python -c \\"import json; f=open('large_tool_results/get_dashboard_by_uid:5'); data=json.load(f); print(data)\\\"")\`
 23→- WRONG: \`execute(command="python -c \\"import json; f=open('/large_tool_results/get_dashboard_by_uid:5'); data=json.load(f); print(data)\\\"")\`
 24→
 25→This applies to ALL file paths used inside execute commands, including paths to files in \`large_tool_results/\` and any other local files.
 26→Note: The filesystem tools (read_file, write_file, ls, etc.) still use absolute paths starting with \`/\` — this restriction only applies to the \`execute\` tool.`;
 27→
 28→/**
 29→ * Middleware that instructs the LLM to use relative paths in execute tool commands,
 30→ * because the VFS sandbox environment does not support absolute paths in shell execution.
 31→ */
 32→const vfsRelativePathMiddleware = createMiddleware({
 33→  name: 'VfsRelativePathMiddleware',
 34→  wrapModelCall: async (request, handler) => {
 35→    const additionalPrompt = new SystemMessage({ content: VFS_RELATIVE_PATH_PROMPT });
 36→    return handler({
 37→      ...request,
 38→      messages: [additionalPrompt, ...request.messages],
 39→    });
 40→  },
 41→});
 42→
 43→/**
 44→ * Middleware that catches "maximum context length" API errors from models
 45→ * that don't natively throw ContextOverflowError (e.g., DeepSeek).
 46→ *
 47→ * Without this, the deepagents summarization middleware's safety net
 48→ * (ContextOverflowError catch → emergency summarization) never triggers,
 49→ * causing unrecoverable 400 errors when token estimation undercounts.
 50→ */
 51→const contextOverflowBridgeMiddleware = createMiddleware({
 52→  name: 'ContextOverflowBridgeMiddleware',
 53→  wrapModelCall: async (request, handler) => {
 54→    try {
 55→      return await handler(request);
 56→    } catch (err: unknown) {
 57→      const message = err instanceof Error ? err.message : String(err);
 58→      if (message.includes('maximum context length')) {
 59→        throw ContextOverflowError.fromError(
 60→          err instanceof Error ? err : new Error(message),
 61→        );
 62→      }
 63→      throw err;
 64→    }
 65→  },
 66→});
 67→
 68→/**
 69→ * Stricter threshold for evicting large tool results to filesystem.
 70→ * Default in deepagents SDK is 20000 tokens (80000 chars).
 71→ * We use 5000 tokens (20000 chars) to aggressively evict large MCP tool results
 72→ * (e.g., query_prometheus, get_dashboard_by_uid) that can return 60k-120k+ chars.
 73→ */
 74→const STRICT_TOOL_TOKEN_LIMIT = 5000;
 75→const NUM_CHARS_PER_TOKEN = 4;
 76→const STRICT_CHAR_LIMIT = STRICT_TOOL_TOKEN_LIMIT * NUM_CHARS_PER_TOKEN;
 77→
 78→/** Tools whose results should never be evicted (same as deepagents SDK). */
 79→const TOOLS_EXCLUDED_FROM_EVICTION = ['ls', 'glob', 'grep', 'read_file', 'edit_file', 'write_file'];
 80→
 81→function sanitizeToolCallId(toolCallId: string): string {
 82→  return toolCallId.replace(/\./g, '_').replace(/\//g, '_').replace(/\\/g, '_');
 83→}
 84→
 85→function createContentPreview(content: string, headLines = 5, tailLines = 5): string {
 86→  const lines = content.split('\n');
 87→  if (lines.length <= headLines + tailLines) {
 88→    return lines.map((line, i) => `${i + 1}\t${line.substring(0, 1000)}`).join('\n');
 89→  }
 90→  const head = lines.slice(0, headLines).map((line, i) => `${i + 1}\t${line.substring(0, 1000)}`).join('\n');
 91→  const truncation = `\n... [${lines.length - headLines - tailLines} lines truncated] ...\n`;
 92→  const tailStart = lines.length - tailLines + 1;
 93→  const tail = lines.slice(-tailLines).map((line, i) => `${tailStart + i}\t${line.substring(0, 1000)}`).join('\n');
 94→  return head + truncation + tail;
 95→}
 96→
 97→const TOO_LARGE_MSG = `Tool result too large, the result of this tool call {tool_call_id} was saved in the filesystem at this path: {file_path}
 98→You can read the result from the filesystem by using the read_file tool, but make sure to only read part of the result at a time.
 99→You can do this by specifying an offset and limit in the read_file tool call.
100→For example, to read the first 100 lines, you can use the read_file tool with offset=0 and limit=100.
101→
102→Here is a preview showing the head and tail of the result (lines of the form
103→... [N lines truncated] ...
104→indicate omitted lines in the middle of the content):
105→
106→{content_sample}`;
107→
108→/**
109→ * Creates a middleware that evicts large tool results to the VFS filesystem
110→ * with a stricter threshold than the default deepagents SDK.
111→ *
112→ * Custom middleware runs innermost in the chain, so our eviction happens
113→ * before the SDK's built-in filesystem middleware sees the result.
114→ */
115→function createStrictToolEvictionMiddleware(backend: SandboxBackendProtocol) {
116→  return createMiddleware({
117→    name: 'StrictToolEvictionMiddleware',
118→    wrapToolCall: async (request, handler) => {
119→      const toolName = request.toolCall?.name;
120→      if (toolName && TOOLS_EXCLUDED_FROM_EVICTION.includes(toolName)) {
121→        return handler(request);
122→      }
123→
124→      const result = await handler(request);
125→
126→      if (ToolMessage.isInstance(result) && typeof result.content === 'string' && result.content.length > STRICT_CHAR_LIMIT) {
127→        const toolCallId = request.toolCall?.id || result.tool_call_id;
128→        const evictPath = `/large_tool_results/${sanitizeToolCallId(toolCallId)}`;
129→
130→        let contentToWrite = result.content;
131→        try {
132→          const parsed = JSON.parse(contentToWrite);
133→          contentToWrite = JSON.stringify(parsed, null, 2);
134→        } catch { }
135→
136→        const writeResult = await backend.write(evictPath, contentToWrite);
137→        if (writeResult.error) return result;
138→
139→        const contentSample = createContentPreview(result.content);
140→        return new ToolMessage({
141→          content: TOO_LARGE_MSG
142→            .replace('{tool_call_id}', result.tool_call_id)
143→            .replace('{file_path}', evictPath)
144→            .replace('{content_sample}', contentSample),
145→          tool_call_id: result.tool_call_id,
146→          name: result.name,
147→          id: result.id,
148→          artifact: (result as any).artifact,
149→          status: result.status,
150→          metadata: result.metadata,
151→          additional_kwargs: result.additional_kwargs,
152→          response_metadata: result.response_metadata,
153→        });
154→      }
155→
156→      return result;
157→    },
158→  });
159→}
