142→async function callAMap<T extends IAmapBaseResponse>(
143→  path: string,
144→  params: Record<string, string | number | boolean | undefined>,
145→): Promise<T> {
146→  const response = await fetch(
147→    `https://restapi.amap.com${path}?${stringify({ key: process.env.AMAP_API_KEY, ...params })}`,
148→    { headers: { 'Content-Type': 'application/json' } },
149→  );
150→
151→  const result = (await response.json()) as T;
152→  if (result.status !== '1') {
153→    const message = '高德 API 调用失败：' + (result.info || '未知错误');
154→    log(message);
155→    throw new Error(message);
156→  }
157→  return result;
158→}
