409→interface TrainRoute {
410→  trainNumber: string;
411→  trainType: string;
412→  departureStation: string;
413→  departureTime: string;
414→  arrivalStation: string;
415→  arrivalTime: string;
416→  duration: string;
417→  distance: string;
418→  tickets: TrainTicket[];
