421→export const getTrainRoute = tool(
422→  async ({ origin, destination, originCityCode, destinationCityCode }) => {
423→    try {
424→      const result = await callAMap<IAmapTransitResponse>(`/v5/direction/transit/integrated`, {
425→        origin,
426→        destination,
427→        city1: originCityCode,
428→        city2: destinationCityCode,
429→      });
430→
431→      const route = result.route;
432→      if (!route || !route.transits || route.transits.length === 0) {
433→        return ['未找到火车路线', new Error('未找到火车路线')];
434→      }
435→
436→      const trainRoutes = route.transits
437→        .map((transit: ITransit) => {
438→          const railSegment = transit.segments.find((segment: ITransitSegment) => segment.railway);
439→          if (!railSegment?.railway) return null;
440→
441→          const railway = railSegment.railway;
442→          const ticketMap = railway.spaces.reduce((acc: Record<string, TrainTicket>, space: IRailwaySpace) => {
443→            const key = `${space.code}_${space.cost}`;
444→            if (!acc[key]) {
445→              acc[key] = {
446→                type: space.code,
447→                price: space.cost + '元',
448→              };
449→            }
450→            return acc;
451→          }, {});
452→
453→          return {
454→            trainNumber: railway.name,
455→            trainType: railway.type,
456→            departureStation: railway.departure_stop.name,
457→            departureTime: railway.departure_stop.time,
458→            arrivalStation: railway.arrival_stop.name,
459→            arrivalTime: railway.arrival_stop.time,
460→            duration: railway.time + '分钟',
461→            distance: railway.distance + '米',
462→            tickets: Object.values(ticketMap),
463→          };
464→        })
465→        .filter((r): r is TrainRoute => r !== null);
466→
467→      if (trainRoutes.length === 0) {
468→        return ['未找到火车路线', new Error('未找到火车路线')];
469→      }
470→
471→      const content = trainRoutes
472→        .map((r: TrainRoute) => {
473→          const ticketInfo = r.tickets.map((t: TrainTicket) => `${t.type}: ${t.price}`).join('\n        ');
474→
475→          return `${r.trainNumber} (${r.trainType})
476→    从 ${r.departureStation} (${r.departureTime}) 
477→    到 ${r.arrivalStation} (${r.arrivalTime})
478→    行程时间: ${r.duration}
479→    行程距离: ${r.distance}
480→    票价信息:
481→        ${ticketInfo}`;
482→        })
483→        .join('\n\n');
484→
485→      return [content, trainRoutes];
486→    } catch (error) {
487→      return ['查询失败', error];
488→    }
489→  },
490→  {
491→    name: EToolName.GetTrainRoute,
492→    description: '查询两个城市之间的火车路线信息，包括车次、时间、票价等详细信息',
493→    schema: z.object({
494→      origin: z.string().describe('起点坐标，如"116.397428,39.90923"'),
495→      destination: z.string().describe('终点坐标，如"121.475079,31.223577"'),
496→      originCityCode: z.string().describe('起点城市编码(citycode)'),
497→      destinationCityCode: z.string().describe('终点城市编码(citycode)'),
498→    }),
499→    responseFormat: 'content_and_artifact',
500→  },
501→);
