 9→  async set(conversation: string, chunk: ILinkedEvent) {
10→    await this.redis.set(`[snapshot]${conversation}.${chunk.id}`, JSON.stringify(chunk));
11→  }
12→
13→  async getTail(conversation: string, tail: string): Promise<ILinkedEvent | null> {
14→    const json = await this.redis.get(`[snapshot]${conversation}.${tail}`);
15→    return json && JSON.parse(json);
16→  }
17→
18→  // 把每个事件都存在redis里作为快照，而且在内容中用next_id作为链穿起来
19→  // 在初次进入conversation时，通过conversation_head + next_id获取整个链表
20→  async *getStream(id: string, head: string, signal: AbortSignal) {
21→    let current: string | undefined = head;
22→    while (current && !signal.aborted) {
23→      const json = await this.redis.get(`[snapshot]${id}.${current}`);
24→      current = undefined;
25→      if (json) {
26→        const chunk: ILinkedEvent = JSON.parse(json);
27→        current = chunk.next_id;
28→        yield chunk;
29→      }
30→    }
31→  }
32→}
33→
34→export interface ILinkedEvent extends IGraphEvent {
35→  next_id?: string;
36→}
