222→  // 返回对应conversation_id的savor
223→  // savor的作用是，通过队列保存chunk，在chunk id一样时覆写，并且构造链表
224→  // 在conversation中保存head和tail，head为了获取整个链表，tail为了继续写入新的链表节点
225→  private async createEventsSaver(id: string) {
226→    const enqueue = this.createQueuedExecutor();
227→    const conversation = await this.conversationModel.findOne({ id });
228→    // 获取对话的最后一个节点的内容
229→    let buffer: ILinkedEvent | null | undefined = conversation?.tail
230→      ? await this.events.getTail(id, conversation.tail)
231→      : null;
232→
233→    return async (chunk?: ILinkedEvent) => {
234→      // 保存后续传入的内容
235→      if (buffer) {
236→        const diff = chunk?.id !== buffer.id;
237→
238→        if (diff) {
239→          // 指向下一个节点
240→          buffer.next_id = chunk?.id;
241→        }
242→
243→        // 保存引用，用在闭包里，避免后面改写引用导致存入的内容丢失
244→        const snapshot = buffer;
245→        // 串行写入。流式事件可能很密集，直接并发 events.set 可能导致顺序错乱或覆盖。队列保证一次只处理一个任务。
246→        enqueue({
247→          key: buffer.id,
248→          func: retry(() => this.events.set(id, snapshot), { interval: 300 }),
249→        });
250→
251→        if (diff) {
252→          const partial: Partial<Conversation> = { tail: buffer.id };
253→          if (buffer.node && TalkableAgents.includes(buffer.node)) {
254→            partial.node = buffer.node;
255→          }
256→          await this.conversationModel.updateOne({ id }, partial);
257→          buffer = chunk;
258→        }
259→      } else if (chunk) {
260→        buffer = chunk;
261→        // 仅在对话没有 head 时才记录（避免因 Redis 丢失 tail 数据时覆盖已有的历史链）
262→        if (!conversation?.head) {
263→          await this.conversationModel.updateOne({ id }, { head: chunk.id });
264→        }
265→      }
266→    };
267→  }
