/**
 * Unwrap the full cause chain of an error for debugging.
 * LangGraph wraps errors through multiple pregel task layers,
 * so the real root cause is often buried deep in the chain.
 */
export function getErrorCauseChain(error: unknown): string[] {
  const chain: string[] = [];
  let current: unknown = error;
  const seen = new WeakSet();

  while (current) {
    if (current instanceof Error) {
      if (seen.has(current)) break;
      seen.add(current);
      const extra: string[] = [];
      // Capture pregelTaskId if present (LangGraph specific)
      if ('pregelTaskId' in current) {
        extra.push(`pregelTaskId=${(current as any).pregelTaskId}`);
      }
      chain.push(`${current.name}: ${current.message}${extra.length ? ` [${extra.join(', ')}]` : ''}`);
      current = current.cause;
    } else if (current && typeof current === 'object') {
      // Some causes are plain objects (e.g., DOMException serialized)
      const obj = current as Record<string, unknown>;
      chain.push(`[Object] ${JSON.stringify(obj).slice(0, 200)}`);
      current = obj.cause;
    } else {
      chain.push(String(current));
      break;
    }
  }

  return chain;
}

